import{_ as a,H as l,f as o,i as t}from"./chunks/framework.DzzgwZ9Y.js";const h=JSON.parse('{"title":"Flags（pflag-like 解析）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/flags.md","filePath":"zh/guide/flags.md"}'),i={name:"zh/guide/flags.md"};function d(c,e,r,s,n,g){return l(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="flags-pflag-like-解析" tabindex="-1">Flags（pflag-like 解析） <a class="header-anchor" href="#flags-pflag-like-解析" aria-label="Permalink to &quot;Flags（pflag-like 解析）&quot;">​</a></h1><h2 id="声明与类型" tabindex="-1">声明与类型 <a class="header-anchor" href="#声明与类型" aria-label="Permalink to &quot;声明与类型&quot;">​</a></h2><p>使用 <code>withFlag(long, short, var, desc, defaultValue)</code> 声明 flag。内置值类型以 C++ 类型为准：</p><ul><li><code>bool/int/int64/uint64/float/double/std::chrono::milliseconds/std::string</code></li><li>额外 helpers：<code>withCountFlag()</code>、<code>withBytesFlag()</code>、<code>withIPFlag/withCIDRFlag/withIPNetFlag/withIPMaskFlag/withURLFlag()</code></li></ul><h2 id="常见解析语义" tabindex="-1">常见解析语义 <a class="header-anchor" href="#常见解析语义" aria-label="Permalink to &quot;常见解析语义&quot;">​</a></h2><ul><li><code>--k=v</code>、<code>-k=v</code>、<code>-k v</code></li><li><code>-abc</code>（short grouping，可配置）</li><li><code>--no-foo</code>（bool negation，可配置）</li><li><code>--</code> 结束 flag 解析</li><li>重复 flag：多次出现时保留 occurrence 顺序</li></ul><h2 id="nooptdefval-可选值" tabindex="-1">NoOptDefVal（可选值） <a class="header-anchor" href="#nooptdefval-可选值" aria-label="Permalink to &quot;NoOptDefVal（可选值）&quot;">​</a></h2><p>通过 <code>markFlagNoOptDefaultValue(&quot;--mode&quot;, &quot;auto&quot;)</code>，允许 <code>--mode</code> 在不带参数时取默认值。 在开启命令遍历时，后续 token 如果是子命令名，不会被当作这个 flag 的值吞掉。</p><h2 id="pflag-风格的-slice-map-取值" tabindex="-1">pflag 风格的 slice/map 取值 <a class="header-anchor" href="#pflag-风格的-slice-map-取值" aria-label="Permalink to &quot;pflag 风格的 slice/map 取值&quot;">​</a></h2><p>Clasp 不强制“typed slice/map flags”，但提供解析辅助（基于重复值/逗号分隔）：</p><ul><li><code>Parser::getStringSlice/getIntSlice/...</code></li><li><code>Parser::getStringToString/getStringToInt/...</code></li></ul>',11)])])}const p=a(i,[["render",d]]);export{h as __pageData,p as default};
